parameters.jsCode:
// Validate required fields
const data = $input.first().json.body;

if (!data.name || !data.email || !data.message) {
  return [{
    json: {
      error: 'Missing required fields'
    }
  }];
}

// Check honeypot
if (data._gotcha) {
  return [{
    json: {
      error: 'Bot detected'
    }
  }];
}

return [{
  json: data
}];

